-- Atribuir papel 'membro' a todos os novos usuários
INSERT INTO user_roles (user_id, role_id)
SELECT u.id, r.id 
FROM users u 
CROSS JOIN roles r 
WHERE r.name = 'membro' 
AND u.id NOT IN (SELECT user_id FROM user_roles)
AND u.email != 'admin@igreja.com';
